"sol": "#include <iostream>\nusing namespace std;\nint main()\n{\n    int R,C,N;\n    cin>>R>>C>>N;\n    int arr[105][105]= {};\n    int k=1;\n    for(int i=0; i<R; i+=1)\n    {\n        for(int j=0; j<C; j+=1)\n        {\n            arr[i][j]=k;\n            k+=1;\n        }\n    }\n\n    N-=1;\n    int right=0,back=0;\n    if(N%2==0) right=N/2;\n    else right=N/2+1;\n    back=N/2;\n\n    for(int a=0; a<right; a+=1)\n    {\n        for(int i=0; i<R; i+=1)\n        {\n            int temp=arr[i][C-1];\n            for(int j=C-1; j>0; j-=1)\n            {\n                arr[i][j]=arr[i][j-1];\n            }\n            arr[i][0]=temp;\n        }\n    }\n    for(int a=0; a<back; a+=1)\n    {\n        for(int j=0; j<C; j+=1)\n        {\n            int temp=arr[R-1][j];\n            for(int i=R-1; i>0; i-=1)\n            {\n                arr[i][j]=arr[i-1][j];\n            }\n            arr[0][j]=temp;\n        }\n    }\n\n    for(int i=0; i<R; i+=1)\n    {\n        for(int j=0; j<C; j+=1)\n        {\n            cout<<arr[i][j];\n            if(j!=C-1) cout<<' ';\n        }\n        if(i!=R-1) cout<<endl;\n    }\n}\n"
