"sol": "#include<bits/stdc++.h>\nint main()\n{\n    long long arr[65]= {0,1};\n    for(long long i=2; i<61; i+=1)\n    {\n        arr[i]=arr[i-1]*2;\n    }\n    long long n,i;\n    scanf(\"%lld%lld\",&n,&i);\n    long long goal=(i-1)^i;\n    long long mov=-1;\n    for(long long j=60; j>=1; j-=1)\n    {\n        if(goal>=arr[j])\n        {\n            mov=j;\n            break;\n        }\n    }\n    long long base=6*arr[mov];\n    long long step=i%base;\n    long long from,to;\n    long long temp=(n+mov)&1;\n    if(step*2 < base)\n    {\n        from=1;\n        if(temp&1)\n        {\n            to=2;\n\n        }\n        else to=3;\n    }\n    else if(step*2 == base)\n    {\n\n        if(temp&1)\n        {\n            from=2;\n            to=3;\n        }\n        else\n        {\n            from=3;\n            to=2;\n        }\n    }\n    else\n    {\n        if(temp&1)\n        {\n            from=3;\n            to=1;\n        }\n        else\n        {\n            from=2;\n            to=1;\n\n        }\n    }\n    printf(\"move %lld from %lld to %lld\\n\",mov,from,to);\n\n}\n\n"
