"sol": "#include<stdio.h>\n#include<iostream>\n#include<vector>\n\nusing namespace std;\nint num;\nvector<int> tree;\nvector<int> v[205];\nint query(int s)\n{\n    int ans = 0;\n    for(int i = 1; i <= s; i++)\n    {\n        ans += tree[i];\n    }\n    return ans;\n}\nint main()\n{\n    double start, end;\n    scanf(\"%d\", &num);\n    tree.resize(num + 1, 1);\n    for(int i = 1; i <= num; i++)\n    {\n        int n;\n        scanf(\"%d\", &n);\n        v[n].push_back(i);\n    }\n    long long ans = 0;\n    for(int i = 1; i <= 200; i++)\n    {\n        for(int j = 0; j < v[i].size(); j++)\n        {\n            int r = query(num) - query(v[i][j]) - (v[i].size() - j - 1);\n            int l = query(v[i][j] - 1);\n            ans += min(l, r);\n            tree[v[i][j]] = 0;\n        }\n    }\n    cout << ans << endl;\n}\n\n"
