"sol": "#include<stdio.h>\n\nint main()\n{\n    int num;\n    scanf(\"%d\",&num); // four digit number\n    int cnt=0,next_num = num;\n    while(num/10>0)\n    {\n        int st = num/100 , ed = num%100;\n        if(st/10>0 && ed/10>0) // if four\n        {\n            int fnt = (st%10) * (st/10);\n            int bk = (ed%10) * (ed/10);\n            if(fnt/10 > 0 && bk/10>0 || fnt/10==0 &&  bk/10>0)\n                num = fnt*100+bk;\n            else if(bk/10==0)\n                num = fnt*10+bk;\n        }\n        else if (st/10>0 && ed<10)// if three(ed is 0x,x=1~9)\n        {\n            int fnt = (st%10) * (st/10);\n            int bk = ed;\n            num = fnt * 10 + bk;\n        }\n        else if (st/10==0 && ed/10>0) // if three(one digit on st)\n        {\n            int fnt = st * (ed/10);\n            int bk = (ed%10) * (ed/10);\n            if(fnt/10 > 0 && bk/10>0 || fnt/10==0 &&  bk/10>0)\n                num = fnt*100+bk;\n            else if(bk/10==0)\n                num = fnt*10+bk;\n        }\n        else if(st/10>0 && ed/10==0)// if three(one digit on ed)\n        {\n            int fnt = (st/10) * (st%10);\n            int bk = ed * (st%10);\n            if(fnt/10 > 0 && bk/10>0 || fnt/10==0 &&  bk/10>0)\n                num = fnt*100+bk;\n            else if(bk/10==0)\n                num = fnt*10+bk;\n        }\n        else if (st/10==0 && ed/10==0)// two digit\n        {\n            num = st*ed;\n        }\n    }\n    printf(\"%d\\n\",num);\n}\n"
