"sol": "//cards.cpp\n#include<cstdio>\n#include<vector>\n#include<cassert>\n#include<algorithm>\nconst int CARD = 50;\nusing namespace std;\n\nint main()\n{\n\tint k, n, m;\n\tvector<vector<int>> next;\n\tvector<int> gt;\n\tvector<vector<int>> pos(CARD);\n\tvector<int> idx(CARD, 0);\n\t\n\tscanf(\"%d%d%d\", &k, &n, &m);\n\t\n\t\n\tnext.resize(k, vector<int>(CARD, -1));\n\tgt.resize(k);\n\t\n\tfor(int i = 0; i < k; ++i)\n\t{\n\t\tscanf(\"%d\", &gt[i]);\n\t\tassert(0 <= gt[i] && gt[i] <= 49);\n\t\tpos[gt[i]].emplace_back(i);\n\t}\n\tfor(int i = 0; i < k; ++i)\n\t{\n\t\tpos[gt[i]].emplace_back(i + k);\n\t}\n\t\n\tfor(int i = 0; i < k; ++i)\n\t{\n\t\tfor(int j = 0; j < CARD; ++j)\n\t\t{\n\t\t\twhile( idx[j] < (int)pos[j].size() && pos[j][idx[j]] <= i) ++idx[j];\n\t\t\tif(idx[j] < (int)pos[j].size()) next[i][j] = pos[j][idx[j]] % k;\n\t\t\telse next[i][j] = -1;\n\t\t}\n\t}\n\t\n\t\n\tfor(int i = 0; i < n; ++i)\n\t{\n\t\tint no, ptr = -1;\n\t\tint round = 0;\n\t\tscanf(\"%d\", &no);\n\t\t\n\t\tif(gt[0] == no) ptr = 0;\n\t\telse ptr = next[0][no];\n\t\t\n\t\tfor(int j = 1; ptr != -1 && j < m; ++j)\n\t\t{\n\t\t\tscanf(\"%d\", &no);\n\t\t\tassert(0 <= no && no <= 49);\n\t\t\tif(ptr >= next[ptr][no] ) ++round;\n\t\t\tptr = next[ptr][no];\n\t\t}\n\t\t\n\t\tif(ptr == -1) printf(\"-1\");\n\t\telse printf(\"%d\\n\", round * k + ptr + 1);\n\t}\n\treturn 0;\n}\n\n"
