"sol": "#include<iostream>\n#include<vector>\n#include<string>\nusing namespace std;\n\nconstexpr int ALPHABET = 26;\nstruct TrieNode\n{\n    int count = 0;\n    TrieNode *child[ALPHABET] = {};\n    ~TrieNode(){ for(int i=0;i<ALPHABET;i+=1) if(child[i])delete child[i]; }\n};\nint main()\n{\n    ios::sync_with_stdio(false);\n\tcin.tie(nullptr);\n    int N;\n    cin >> N;\n    vector<string> names(N);\n    for(int i=0;i<N;++i)\n    {\n        cin >> names[i];\n    }\n\n    TrieNode *root = new TrieNode;\n    for(auto &s:names)\n    {\n        TrieNode *cur = root;\n        for(auto &c:s)\n        {\n            if(cur->child[c-'A']==nullptr)\n                cur->child[c-'A'] = new TrieNode;\n            cur = cur->child[c-'A'];\n            cur->count += 1;\n        }\n    }\n    for(auto &s:names)\n    {\n        TrieNode *cur = root;\n        int cnt = 0;\n        for(auto &c:s)\n        {\n            cur = cur->child[c-'A'];\n            cnt += cur->count;\n        }\n        cout << cnt-s.size() << \"\\n\";\n    }\n    delete root;\n    return 0;\n}\n"
