"sol": "#include<iostream>\n#include<vector>\n#include<algorithm>\n#include<utility>\n#include<string>\n#include<queue>\nusing namespace std;\n\nint main()\n{\n    int H, W;\n    cin >> H >> W;\n    vector<string> table(H);\n    for(int i=0; i<H; ++i)\n        cin >> table[i];\n    int K;\n    cin >> K;\n\n    vector<int> ans(K);\n    queue<pair<int,int>> bfs;\n    for(int i=0; i<H; ++i)\n    {\n        for(int j=0; j<W; ++j)\n        {\n            if(table[i][j]=='-')\n            {\n                bfs.push(make_pair(i, j));\n            }\n        }\n    }\n    constexpr int dirs[5] = {0, -1, 0, 1, 0};\n    int steps = 0;\n    while(!bfs.empty())\n    {\n        int siz = bfs.size();\n        for(int k=0; k<siz; ++k)\n        {\n            int x = bfs.front().first;\n            int y = bfs.front().second;\n            bfs.pop();\n            for(int d=0; d<4; ++d)\n            {\n                int new_x = x + dirs[d];\n                int new_y = y + dirs[d+1];\n                if(new_x < H && new_x >= 0 && new_y < W && new_y >= 0 && table[new_x][new_y]=='*')\n                {\n                    table[new_x][new_y] = '-';\n                    bfs.push(make_pair(new_x, new_y));\n                    ans[steps] += 1;\n                }\n            }\n        }\n        steps += 1;\n        if(steps==K)steps = 0;\n    }\n    for(auto &i: ans)\n        cout << i << ' ';\n\n    return 0;\n}\n"
