"sol": "#include<iostream>\n#include<vector>\nusing namespace std;\n\nint main()\n{\n    int R, C;\n    cin >> R >> C;\n    vector<vector<int>> diff(R+1, vector<int>(C+1, 0));\n\n    int Q;\n    cin >> Q;\n    for(int i=0; i<Q; i+=1)\n    {\n        int data[5];\n        for(int j=0; j<5; j+=1)cin >> data[j];\n        diff[data[0]][data[1]] += data[4];\n        diff[data[0]][data[3]] -= data[4];\n        diff[data[2]][data[1]] -= data[4];\n        diff[data[2]][data[3]] += data[4];\n    }\n\n    int rowsum = 0;\n    for(int j=0; j<C; ++j)\n    {\n        rowsum += diff[0][j];\n        diff[0][j] = rowsum;\n        cout << diff[0][j] << ' ';\n    }\n    cout << '\\n';\n    for(int i=1; i<R; ++i)\n    {\n        rowsum = 0;\n        for(int j=0; j<C; ++j)\n        {\n            rowsum += diff[i][j];\n            diff[i][j] = rowsum + diff[i-1][j];\n            cout << diff[i][j] << ' ';\n        }\n        cout << '\\n';\n    }\n\n    return 0;\n}\n"
