"sol": "#include <iostream>\n#include <vector>\nusing namespace std;\n\n// nonogram\nint main()\n{\n    int n;\n    cin >> n;\n    vector<vector<bool>> grid(n, vector<bool>(n));\n    for (int r = 0; r < n; ++r)\n    {\n        for (int c = 0; c < n; ++c)\n        {\n            bool b;\n            cin >> b;\n            grid[r][c] = b;\n        }\n    }\n    // check columns\n    for (int c = 0; c < n; ++c)\n    {\n        bool isEmpty = true;\n        int count = 0;\n        for (int r = 0; r < n; ++r)\n        {\n            if (grid[r][c])\n            {\n                ++count;\n                isEmpty = false;\n            }\n            else if (count > 0)\n            {\n                cout << count << \" \";\n                count = 0;\n            }\n        }\n        if (count > 0)\n        {\n            cout << count << \" \";\n        }\n        else if (isEmpty)\n        {\n            cout << \"0\";\n        }\n        cout << endl;\n    }\n    // check rows\n    for (int r = 0; r < n; ++r)\n    {\n        bool isEmpty = true;\n        int count = 0;\n        for (int c = 0; c < n; ++c)\n        {\n            if (grid[r][c])\n            {\n                ++count;\n                isEmpty = false;\n            }\n            else if (count > 0)\n            {\n                cout << count << \" \";\n                count = 0;\n            }\n        }\n        if (count > 0)\n        {\n            cout << count << \" \";\n        }\n        else if (isEmpty)\n        {\n            cout << \"0\";\n        }\n        cout << endl;\n    }\n}"
