"sol": "#include <iostream>\n#include <cmath>\n\nusing namespace std;\n\nbool isPrime(int n)\n{\n    for (int i = 2; i <= sqrt(n); i++)\n    {\n        if (n % i == 0)\n            return false;\n    }\n    return true;\n}\n\nint main()\n{\n    int n, cur;\n    cin >> n;\n    // prime\n    cur = n;\n    while (cur++)\n    {\n        if (isPrime(cur))\n        {\n            cout << cur << \" \";\n            break;\n        }\n    }\n\n    // ^2\n    cur = 1;\n    while (cur++)\n    {\n        if (cur * cur > n)\n        {\n            cout << cur * cur << \" \";\n            break;\n        }\n    }\n\n    // ^3\n    cur = 1;\n    while (cur++)\n    {\n        if (cur * cur * cur > n)\n        {\n            cout << cur * cur * cur << endl;\n            break;\n        }\n    }\n}"
