"sol": "#include <iostream>\nusing namespace std;\n\nint main()\n{\n    int n; // 食材數量\n    int a; // 原始份數\n    cin >> n >> a;\n    int x[10010]; // 所有食材重量\n    for (int i = 0; i < n; i++)\n    {\n        cin >> x[i]; // 食材重量\n    }\n    int b;\n    cin >> b; // 欲製作人數\n\n    for (int i = 0; i < n; i++)\n    {\n        // 計算每種食材的重量\n        if ((x[i] * b) % a != 0)\n            x[i] = x[i] * b / a + 1; // 如果無法整除，則向上取整\n        else\n            x[i] = x[i] * b / a; // 否則直接取整\n\n        cout << x[i] << \" \"; // 輸出每種食材的重量\n    }\n    cout << endl;\n\n    return 0;\n}"
