"sol": "#include<stdio.h>\n\nint main()\n{\n\tint input = 0, time = 0;\n\tscanf(\"%d %d\", &input, &time);\n\n\tint logic[101] = {};\n\tfor( int i=1; i<=input*time; i+=1 ){\n\t\tscanf(\"%d\", &logic[i]);\n\t}\n\n\tprintf(\"input = %d\\n\", input);\n\tint AND[11]={}, OR[11]={}, XOR[11]={};\n\tfor( int i=1; i<=time; i+=1 )\n\t{\n\t\tint num_1 = 0;\n\t\tfor( int j=0; j<input; j+=1 )\n\t\t{\t\n\t\t\tif( logic[i + j*time] == 1 )\n\t\t\t{\n\t\t\t\tOR[i] = 1;\n\t\t\t\tnum_1 += 1;\n\t\t\t}\n\t\t}\n\n\t\tprintf(\"num 1: %d\\n\",num_1 );\n\t\tif( num_1 % 2 == 1 )\n\t\t\tXOR[i] = 1;\n\t\tif( num_1 == input )\n\t\t\tAND[i] = 1;\n\t}\n\n\tprintf(\"AND:\");\n\tfor( int i=1; i<=time ; i+=1){\n\t\tprintf(\" %d\", AND[i]);\n\t}\n\tprintf(\"\\n\");\n\n\tprintf(\" OR:\");\n\tfor( int i=1; i<=time ; i+=1){\n\t\tprintf(\" %d\", OR[i]);\n\t}\n\tprintf(\"\\n\");\n\n\tprintf(\"XOR:\");\n\tfor( int i=1; i<=time ; i+=1){\n\t\tprintf(\" %d\", XOR[i]);\n\t}\n\tprintf(\"\\n\");\n}"
