"sol": "#include<bits/stdc++.h>\nint multi[10000005]={};\nint add[10000005]={};\nint divi[10000005]={};\nint main()\n{\n    for(int i=0;i<10000005;i+=1)\n    {\n        multi[i]=1;\n        divi[i]=1;\n    }\n    int N,M;\n    scanf(\"%d%d\",&N,&M);\n    for(int i=0;i<M;i+=1)\n    {\n        int p,q,r,s;\n        scanf(\"%d%d%d%d\",&p,&q,&r,&s);\n        if(r==1)\n        {\n            add[p]+=s;\n            add[q+1]-=s;\n        }\n        else if(r==2)\n        {\n            multi[p]*=s;\n            divi[q+1]*=s;\n        }\n    }\n    int big=0,bigind=1;\n    int base=1,x=0;\n    for(int i=1;i<=N;i+=1)\n    {\n\n        base*=multi[i];\n        base/=divi[i];\n        x+=add[i];\n        //printf(\"%d %d\\n\",base,x);\n        if(big<x*base)\n        {\n            big=x*base;\n            bigind=i;\n        }\n    }\n    printf(\"%d %d\\n\",bigind,big);\n}\n"
