"sol": "#include<iostream>\nusing namespace std;\nint main()\n{\n\tint N;\n\tcin >> N;\n\tint checkers[105][105] = {};\n\tfor(int i = 0; i < 105; i++)\n\t{\n\t\tfor(int j = 0; j < 105; j++)\n\t\t{\n\t\t\tcheckers[i][j] = -1;\n\t\t}\n\t}\n\tfor(int i = 1; i <= N; i++)\n\t{\n\t\tfor(int j = 1; j <= N; j++)\n\t\t{\n\t\t\tcin >> checkers[i][j];\n\t\t}\n\t}\n\tint x, y, d;\n\tint dir[3][2] = {{1, 0}, {1, 1}, {0, 1}};\n\tbool ans = true;\n\tcin >> x >> y >> d;\n\tif(checkers[x + dir[d][0]][y + dir[d][1]] == 0)  //平移\n\t{\n\t\tcheckers[x + dir[d][0]][y + dir[d][1]] = 1;\n\t\tcheckers[x][y] = 0;\n\t}\n\telse if(checkers[x + dir[d][0]][y + dir[d][1]] == -1)\n\t{\n\t\tcout << \"Impossible\" << endl;\n\t\tans = false;\n\t}\n\telse\n\t{\n\t\tif(checkers[x + dir[d][0] * 2][y + dir[d][1] * 2] == 0) //跳躍\n\t\t{\n\t\t\tcheckers[x][y] = 0;\n\t\t\twhile(checkers[x + dir[d][0] * 2][y + dir[d][1] * 2]==0)\n\t\t\t{\n\t\t\t\tx = x + dir[d][0] * 2;\n\t\t\t\ty = y + dir[d][1] * 2;\n\t\t\t}\n\t\t\tcheckers[x][y] = 1;\n\t\t\t\n\t\t}\n\t\telse\n\t\t{\n\t\t\tcout << \"Impossible\" << endl;\n\t\t\tans = false;\n\t\t}\n\t}\n\tif(ans)\n\t{\n\t\tfor(int i = 1; i <= N; i++)\n\t\t{\n\t\t\tfor(int j = 1; j <= N; j++)\n\t\t\t{\n\t\t\t\tcout << checkers[i][j];\n\t\t\t\tif(j != N) cout << \" \";\n\t\t\t}\n\t\t\tcout << \"\\n\";\n\t\t}\n\t}\n\n}\n"
