"sol": "\n#include<stdio.h>\n\nint C[3001][501];\n\nint solve(int m, int n)\n{\n\tif(m < 0 || m < n) return 0;\n\tfor(int i = 0; i <= m; ++i)\n\t{\n\t\tfor(int j = 0; j <= i && j <= n; ++j)\n\t\t{\n\t\t\tif(j == 0 || j == i) C[i][j] = 1;\n\t\t\telse C[i][j] = (C[i-1][j-1] + C[i-1][j]) % 1000000007;\n\t\t}\n\t}\n\treturn C[m][n];\n}\n\nint main()\n{\n\tint w, n, sum = 0;\n\tscanf(\"%d%d\", &w, &n);\n\tfor(int i = 0; i < n; ++i)\n\t{\n\t\tint tmp;\n\t\tscanf(\"%d\", &tmp);\n\t\tsum += tmp;\n\t}\n\t\n\tprintf(\"%d\\n\", solve(w - sum + 1, n));\n\t\n\treturn 0;\n}\n"
