"sol": "#include <iostream>\n#include <algorithm>\nusing namespace std;\nstruct block\n{\n\tint ux, uy;\n\tint dx, dy;\n\tint weight, id;\n\tbool exist;\n};\n\nbool cmp_w(block a, block b)\n{\n\tif(a.weight == b.weight) return a.id < b.id;\n\treturn a.weight > b.weight;\n}\n\nbool cmp_id(block a, block b)\n{\n\treturn a.id < b.id;\n}\n\nbool overlap(block a, block b)\n{\n\tint inter_area = 0, union_area = 0;\n\tint ixmin, iymin, ixmax, iymax;\n\n\tixmin = max(a.ux, b.ux);\n\tiymin = max(a.uy, b.uy);\n\tixmax = min(a.dx, b.dx);\n\tiymax = min(a.dy, b.dy);\n\tinter_area = max(ixmax - ixmin, 0) * max(iymax - iymin, 0);\n\n\tint A = (a.dx - a.ux) * (a.dy - a.uy);\n\tint B = (b.dx - b.ux) * (b.dy - b.uy);\n\tunion_area = A + B - inter_area;\n\treturn inter_area * 4 > union_area;\n}\n\nint main()\n{\n\tint N;\n\tcin >> N;\n\tblock blks[101] = {};\n\tfor(int i=0; i<N; i++)\n\t{\n\t\tcin >> blks[i].ux >> blks[i].uy;\n\t\tcin >> blks[i].dx >> blks[i].dy;\n\t\tcin >> blks[i].weight;\n\t\tblks[i].exist = true;\n\t\tblks[i].id = i + 1;\n\t}\n\n\tsort(blks, blks+N, cmp_w);\n\n\tfor(int i=0; i<N; i++)\n\t{\n\t\tif(blks[i].exist) \n\t\t{\n\t\t\tfor(int j=i+1; j<N; j++)\n\t\t\t{\n\t\t\t\tif(blks[j].exist && overlap(blks[i], blks[j]))\n\t\t\t\t{\n\t\t\t\t\tblks[j].exist = false;\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\n\tbool ans = false;\n\tsort(blks, blks+N, cmp_id);\n\tfor(int i=0; i<N; i++)\n\t{\n\t\tif(blks[i].exist)\n\t\t{\n\t\t\tif(ans) cout << \" \";\n\t\t\tcout << blks[i].id;\n\t\t\tans = true;\n\t\t}\n\t}\n\tcout << endl;\n}"
