"sol": "#include <iostream>\n#include <string>\n\nusing namespace std;\n\nbool cmp(int feq1[26], int feq2[26])\n{\n    for (int i = 0; i < 26; ++i)\n    {\n        if (feq1[i] != feq2[i])\n        {\n            return false;\n        }\n    }\n    return true;\n}\n\nint main()\n{\n    int N;\n    cin >> N;\n    int word_feq[N][26] = {0}, col_feq[N][26] = {0};\n    string S[N];\n    for (int i = 0; i < N; ++i)\n    {\n        cin >> S[i];\n        for (size_t l = 0; l < S[i].length(); ++l)\n        {\n            word_feq[i][S[i][l] - 'a']++;\n            if (l < N)\n            {\n                col_feq[l][S[i][l] - 'a']++;\n            }\n        }\n    }\n\n    for (int i = 0; i < N; ++i)\n    {\n        for (int j = 0; j < N; ++j)\n        {\n            if (cmp(word_feq[i], col_feq[j]))\n            {\n                cout << S[i] << endl;\n            }\n        }\n    }\n}"
