"sol": "#include <iostream>\nusing namespace std;\n\nint N;\nint ans = INT_MAX;\nbool visited[55] = {};\nint ticket[55][55] = {};\n\nvoid dfs(int s, int t, int cost)\n{\n\tif(s == t) {\n\t\tans = min(ans, cost);\n\t\treturn;\n\t}\n\tvisited[s] = true;\n\tfor(int i=0; i<N; i++) {\n\t\tif(ticket[s][i] != -1 && !visited[i]){\n\t\t\tvisited[i] = true;\n\t\t\tint tmp = cost + ticket[s][i];\n\t\t\tif(cost > 0) tmp -= 50;\n\t\t\tdfs(i, t, tmp);\n\t\t\tvisited[i] = false;\n\t\t}\n\t}\n}\n\nint main()\n{\n\tcin >> N;\n\tfor(int i=0; i<N; i++) {\n\t\tfor(int j=0; j<N; j++) {\n\t\t\tcin >> ticket[i][j];\n\t\t}\n\t}\n\tint src, trg;\n\tcin >> src >> trg;\n\tdfs(src-1, trg-1, 0);\n\tcout << ans << endl;\n}\n"
