"sol": "#include <iostream>\n#include <vector>\nusing namespace std;\n\n\nint main()\n{\n\tcin.sync_with_stdio(0);\n        cin.tie(0);\n\tint n, m;\n\tcin >> n >> m;\n\tvector<vector<int>> v(n, vector<int>(m));\n\tfor(int i = 0; i < n; ++i)\n\t{\n\t\tfor(int j= 0; j < m; ++j)\n\t\t{\n\t\t\tcin >> v[i][j];\n\t\t}\n\t}\n\tfor(int i = 1; i < n; ++i)\n\t{\n\t\tv[i][0] += v[i-1][0];\n\t}\n\n\tfor(int j = 1; j < m; ++j)\n\t{\n\t\tv[0][j] += v[0][j-1];\n\t}\n\n\tfor(int i = 1; i < n; ++i)\n\t{\n\t\tfor(int j= 1; j < m; ++j)\n\t\t{\n\t\t\tv[i][j] += max(v[i][j-1], v[i-1][j]); \n\t\t}\n\t}\n\n\tcout << v[n-1][m-1] << endl;\n\treturn 0;\n}"
